package genxsolution.vms.vmsbackend.employee_hr_management.payroll.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.employee_hr_management.payroll.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.payroll.service.PayrollService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/hr/payrolls") public class PayrollController { private final PayrollService service; public PayrollController(PayrollService service){this.service=service;} @GetMapping public List<PayrollResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public PayrollResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public PayrollResponse create(@RequestBody PayrollUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public PayrollResponse update(@PathVariable UUID id,@RequestBody PayrollUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
